    person_uuid, 
    observation_type, 
    CAST(observation_date AS DATE), 
    CAST(observation_data AS JSONB), 
    CAST(facility_id AS INTEGER), 
    creator, 
    CAST(created_at AS TIMESTAMP), 
    modifier, 
    CAST(modified_at AS TIMESTAMP), 
    0, 
    gen_random_uuid()
FROM tb_backlog;